          'code': code,\n                        'date': date,\n                        'type': signal['type'],\n                        'pct_change': signal['pct_change'],\n                        'closing_position': closing_pos,\n                        'continuation': '是' if continuation else '否'\n                    })\n\n    return results\n\ndef main():\n    print(\"开始检测盘中异动信号...\")\n\n    # 获取最近5个交易日\n    trading_days = get_recent_trading_days(5)\n    print(f\"最近5个交易日: {trading_days}\")\n\n    if len(trading_days) == 0:\n        print(\"无法获取交易日数据\")\n        with open('intraday_signal.txt', 'w', encoding='utf-8') as f:\n            f.write(\"股票代码,异动日期,异动类型,异动幅度(%),当日收盘位置(%),次日是否持续\\n\")\n            f.write(\"# 数据源限制：无法获取交易日数据\\n\")\n        return\n\n    # 获取股票列表（使用部分样本）\n    client = quotes.Quotes.factory(market='std')\n    try:\n        stocks_df = client.stocks(market='sh')\n        stock_codes = stocks_df['code'].tolist()[:100]  # 取前100只股票作为样本\n    except:\n        # 如果无法获取列表，使用预定义样本\n        stock_codes = [\n            '000001', '000002', '000004', '000005', '000006',\n            '000007', '000008', '000009', '000010', '000011',\n            '600000', '600004', '600005', '600006', '600007',\n            '600008', '600009', '600010', '600011', '600012'\n        ]\n\n    print(f\"扫描 {len(stock_codes)} 只股票...\")\n\n    # 扫描股票\n    results = scan_stocks(stock_codes, trading_days)\n\n    # 写入结果\n    output_file = 'intraday_signal.txt'\n    with open(output_file, 'w', encoding='utf-8') as f:\n        f.write(\"股票代码,异动日期,异动类型,异动幅度(%),当日收盘位置(%),次日是否持续\\n\")\n\n        if len(results) == 0:\n            f.write(\"# 在扫描的股票中未发现符合条件的异动信号\\n\")\n            f.write(\"# 检测条件：\\n\")\n            f.write(\"# 1. 急拉：30分钟涨幅>5%，成交量>前期均量5倍\\n\")\n            f.write(\"# 2. V型反转：跌>3%后2个K线收复，成交量>前期均量5倍\\n\")\n            f.write(\"# 3. 当日收盘位置>60%\\n\")\n            f.write(\"# 4. 次日收盘不跌破当日最低价\\n\")\n        else:\n            for r in results:\n                f.write(f\"{r['code']},{r['date']},{r['type']},{r['pct_change']:.2f},{r['closing_position']:.1f},{r['continuation']}\\n\")\n\n    print(f\"检测完成，发现 {len(results)} 个异动信号\")\n    print(f\"结果已写入 {output_file}\")\n\nif __name__ == '__main__':\n    main()\n","structuredPatch":[],"originalFile":null}}
