 if df is None or len(df) < 6:\n            continue\n\n        success_count += 1\n        signals = detect_intraday_anomaly_from_daily(df)\n\n        for signal in signals:\n            all_results.append({\n                'code': code,\n                **signal\n            })\n\n    print(f\"成功获取 {success_count} 只股票数据\")\n    print(f\"发现 {len(all_results)} 个异动信号\")\n\n    # 写入结果\n    output_file = 'intraday_signal.txt'\n    with open(output_file, 'w', encoding='utf-8') as f:\n        f.write(\"股票代码,异动日期,异动类型,异动幅度(%),当日收盘位置(%),次日是否持续\\n\")\n\n        if len(all_results) == 0:\n            f.write(\"# 在最近5个交易日内未发现符合条件的异动信号\\n\")\n            f.write(\"# 数据说明：由于mootdx数据源限制，使用日K线数据近似检测盘中异动\\n\")\n            f.write(\"# 检测逻辑：\\n\")\n            f.write(\"#   急拉信号：日振幅>8%，收盘位置>60%，成交量>前5日均量3倍\\n\")\n            f.write(\"#   V型反转：下影线长>50%，收盘位置>60%，成交量>前5日均量3倍\\n\")\n            f.write(\"#   后续验证：次日收盘不跌破当日最低价\\n\")\n        else:\n            # 按日期排序\n            all_results.sort(key=lambda x: x['date'], reverse=True)\n\n            # 只保留最近5个交易日的数据\n            if len(all_results) > 0:\n                latest_dates = sorted(set(r['date'] for r in all_results), reverse=True)[:5]\n                filtered_results = [r for r in all_results if r['date'] in latest_dates]\n\n                for r in filtered_results:\n                    continuation_str = '是' if r['continuation'] else '否'\n                    f.write(f\"{r['code']},{r['date']},{r['type']},{r['amplitude']:.2f},{r['closing_position']:.1f},{continuation_str}\\n\")\n\n    print(f\"结果已写入 {output_file}\")\n\nif __name__ == '__main__':\n    main()\n","structuredPatch":[{"oldStart":2,"oldLines":6,"newStart":2,"newLines":7,"lines":[" # -*- coding: utf-8 -*-"," \"\"\""," 盘中异动信号检测 - 急拉和V型反转","+使用日K线数据近似检测（由于30分钟数据限制）"," \"\"\""," import sys"," sys.path.insert(0, '/Users/tomato/Documents/potato/project/YFD')"]},{"oldStart":12,"oldLines":146,"newStart":13,"newLines":7,"lines":[" import warnings"," warnings.filterwarni