mootdx import quotes\nimport pandas as pd\nfrom datetime import datetime, timedelta\nimport warnings\nwarnings.filterwarnings('ignore')\n\ndef get_recent_trading_days(n=5):\n    \"\"\"获取最近N个交易日\"\"\"\n    client = quotes.Quotes.factory(market='std')\n    # 使用一个常见股票获取交易日历\n    df = client.bars(symbol='000001', frequency=9, offset=0)\n    if len(df) == 0:\n        return []\n    dates = pd.to_datetime(df.index).date\n    unique_dates = sorted(set(dates), reverse=True)\n    return unique_dates[:n]\n\ndef get_30min_data(code, days=10):\n    \"\"\"获取30分钟K线数据\"\"\"\n    client = quotes.Quotes.factory(market='std')\n    try:\n        # frequency=9 表示30分钟K线\n        df = client.bars(symbol=code, frequency=9, offset=0)\n        if len(df) == 0:\n            return None\n        df.index = pd.to_datetime(df.index)\n        return df\n    except:\n        return None\n\ndef detect_surge_signal(df_30min, date):\n    \"\"\"\n    检测急拉信号：\n    - 单个30分钟K线涨幅 > 5%\n    - 成交量 > 前几个时段均量的5倍\n    \"\"\"\n    signals = []\n    df_date = df_30min[df_30min.index.date == date]\n\n    if len(df_date) < 2:\n        return signals\n\n    for i in range(1, len(df_date)):\n        curr = df_date.iloc[i]\n        prev = df_date.iloc[i-1]\n\n        # 计算涨幅\n        if prev['close'] > 0:\n            pct_change = (curr['close'] - prev['close']) / prev['close'] * 100\n\n            if pct_change > 5.0:\n                # 检查成交量放大\n                if i >= 2:\n                    prev_volumes = df_date.iloc[:i]['volume'].values\n                    avg_volume = prev_volumes.mean()\n\n                    if avg_volume > 0 and curr['volume'] > avg_volume * 5:\n                        signals.append({\n                            'time': curr.name,\n                            'type': '急拉',\n                            'pct_change': pct_change,\n                            'volume_ratio': curr['volume'] / avg_volume\n                        })\n\n    return signals\n\ndef detect_v_reversal(df_30min, date):\n    \"\"\"\n    检测V型反转：\n    - 30分钟跌幅 > 3%\n    - 随后连续2个30分钟K线反弹收复失地\n    - 成交量 > 前几个时段均量的5倍\n    \"\"\"\n    signals = []\n    df_date = df_30min[df_30min.index.date == date]\n\n    if len(df_date) < 4:\n        return signals\n\n    for i in range(1, len(df_date) - 2):\n        curr = df_date.iloc[i]\n        prev = df_date.iloc[i-1]\n        next1 = df_date.iloc[i+1]\n        next2 = df_date.iloc[i+2]\n\n        # 检测跌幅 > 3%\n        if prev['close'] > 0:\n            pct_drop = (curr['close'] - prev['close']) / prev['close'] * 100\n\n            if pct_drop < -3.0:\n                # 检查后续2个K线是否收复\n                if next2['close'] >= prev['close'] * 0.99:  # 允许小幅误差\n                    # 检查成交量放大\n                    if i >= 2:\n                        prev_volumes = df_date.iloc[:i]['volume'].values\n                        avg_volume = prev_volumes.mean()\n\n                        # 检查反弹时段的成交量\n                        reversal_volume = max(next1['volume'], next2['volume'])\n                        if avg_volume > 0 and reversal_volume > avg_volume * 5:\n                            signals.append({\n                                'time': next2.name,\n                                'type': 'V型反转',\n                                'pct_change': abs(pct_drop),\n                                'volume_ratio': reversal_volume / avg_volume\n                            })\n\n    return signals\n\ndef verify_closing_position(df_day, date):\n    \"\"\"验证当日收盘价位于全日振幅的上60%\"\"\"\n    try:\n        df_date = df_day[df_day.index.date == date]\n        if len(df_date) == 0:\n            return None\n\n        row = df_date.iloc[0]\n        high = row['high']\n        low = row['low']\n        close = row['close']\n\n        if high == low:\n            return 100.0\n\n        position = (close - low) / (high - low) * 100\n        return position\n    except:\n        return None\n\ndef verify_next_day_continuation(df_day, date, next_date):\n    \"\"\"验证次日收盘价不跌破异动日最低价\"\"\"\n    try:\n        df_curr = df_day[df_day.index.date == date]\n        df_next = df_day[df_day.index.date == next_date]\n\n        if len(df_curr) == 0 or len(df_next) == 0:\n            return None\n\n        curr_low = df_curr.iloc[0]['low']\n        next_close = df_next.iloc[0]['close']\n\n        return next_close >= curr_low\n    except:\n        return None\n\ndef get_daily_data(code):\n    \"\"\"获取日K线数据\"\"\"\n    client = quotes.Quotes.factory(market='std')\n    try:\n        df = client.bars(symbol=code, frequency=9, offset=0)\n        if len(df) == 0:\n            return None\n\n        # 转换为日K线\n        df.index = pd.to_datetime(df.index)\n        df_daily = df.resample('D').agg({\n            'open': 'first',\n            'high': 'max',\n            'low': 'min',\n            'close': 'last',\n            'volume': 'sum'\n        }).dropna()\n\n        return df_daily\n    except:\n        return None\n\ndef scan_stocks(stock_codes, trading_days):\n    \"\"\"扫描股票列表\"\"\"\n    results = []\n\n    for code in stock_codes:\n        print(f\"扫描 {code}...\")\n\n        # 获取30分钟数据\n        df_30min = get_30min_data(code, days=10)\n        if df_30min is None or len(df_30min) == 0:\n            continue\n\n        # 获取日K线数据\n        df_daily = get_daily_data(code)\n        if df_daily is None or len(df_daily) == 0:\n            continue\n\n        # 检测每个交易日\n        for idx, date in enumerate(trading_days):\n            # 检测急拉信号\n            surge_signals = detect_surge_signal(df_30min, date)\n            for signal in surge_signals:\n                # 验证收盘位置\n                closing_pos = verify_closing_position(df_daily, date)\n                if closing_pos is None or closing_pos < 60:\n                    continue\n\n                # 验证次日持续\n                if idx < len(trading_days) - 1:\n                    next_date = trading_days[idx + 1]\n                    continuation = verify_next_day_continuation(df_daily, date, next_date)\n                    if continuation is None:\n                        continue\n\n                    results.append({\n                        'code': code,\n                        'date': date,\n                        'type': signal['type'],\n                        'pct_change': signal['pct_change'],\n                        'closing_position': closing_pos,\n                        'continuation': '是' if continuation else '否'\n                    })\n\n            # 检测V型反转信号\n            v_signals = detect_v_reversal(df_30min, date)\n            for signal in v_signals:\n                # 验证收盘位置\n                closing_pos = verify_closing_position(df_daily, date)\n                if closing_pos is None or closing_pos < 60:\n                    continue\n\n                # 验证次日持续\n                if idx < len(trading_days) - 1:\n                    next_date = trading_days[idx + 1]\n                    continuation = verify_next_day_continuation(df_daily, date, next_date)\n                    if continuation is None:\n                        continue\n\n                    results.append({\n                        'code': code,\n                        'date': date,\n                        'type': signal['type'],\n                        'pct_change': signal['pct_change'],\n                        'closing_position': closing_pos,\n                        'continuation': '是' if continuation else '否'\n                    })\n\n    return results\n\ndef main():\n    print(\"开始检测盘中异动信号...\")\n\n    # 获取最近5个交易日\n    trading_days = get_recent_trading_days(5)\n    print(f\"最近5个交易日: {trading_days}\")\n\n    if len(trading_days) == 0:\n        print(\"无法获取交易日数据\")\n        with open('intraday_signal.txt', 'w', encoding='utf-8') as f:\n            f.write(\"股票代码,异动日期,异动类型,异动幅度(%),当日收盘位置(%),次日是否持续\\n\")\n            f.write(\"# 数据源限制：无法获取交易日数据\\n\")\n        return\n\n    # 获取股票列表（使用部分样本）\n    client = quotes.Quotes.factory(market='std')\n    try:\n        stocks_df = client.stocks(market='sh')\n        stock_codes = stocks_df['code'].tolist()[:100]  # 取前100只股票作为样本\n    except:\n        # 如果无法获取列表，使用预定义样本\n        stock_codes = [\n            '000001', '000002', '000004', '000005', '000006',\n            '000007', '000008', '000009', '000010', '000011',\n            '600000', '600004', '600005', '600006', '600007',\n            '600008', '600009', '600010', '600011', '600012'\n        ]\n\n    print(f\"扫描 {len(stock_codes)} 只股票...\")\n\n    # 扫描股票\n    results = scan_stocks(stock_codes, trading_days)\n\n    # 写入结果\n    output_file = 'intraday_signal.txt'\n    with open(output_file, 'w', encoding='utf-8') as f:\n        f.write(\"股票代码,异动日期,异动类型,异动幅度(%),当日收盘位置(%),次日是否持续\\n\")\n\n        if len(results) == 0:\n            f.write(\"# 在扫描的股票中未发现符合条件的异动信号\\n\")\n            f.write(\"# 检测条件：\\n\")\n            f.write(\"# 1. 急拉：30分钟涨幅>5%，成交量>前期均量5倍\\n\")\n            f.write(\"# 2. V型反转：跌>3%后2个K线收复，成交量>前期均量5倍\\n\")\n            f.write(\"# 3. 当日收盘位置>60%\\n\")\n            f.write(\"# 4. 次日收盘不跌破当日最低价\\n\")\n        else:\n            for r in results:\n                f.write(f\"{r['code']},{r['date']},{r['type']},{r['pct_change']:.2f},{r['closing_position']:.1f},{r['continuation']}\\n\")\n\n    print(f\"检测完成，发现 {len(results)} 个异动信号\")\n    print(f\"结果已写入 {output_file}\")\n\nif __name__ == '__main__':\n    main()\n"}}
